import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as n,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Automatische tags","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/auto-tagging.md","filePath":"nl-NL/Other/auto-tagging.md","lastUpdated":1781962217000}'),r={name:"nl-NL/Other/auto-tagging.md"};function d(s,e,l,g,p,c){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="automatische-tags" tabindex="-1">Automatische tags <a class="header-anchor" href="#automatische-tags" aria-label="Permalink to &quot;Automatische tags&quot;">​</a></h1><p>Automatische tags stel je in onder:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Deze functie genereert automatisch afbeeldingstags. Die zijn handig voor zoeken, filters in de Random Image API, filtering in de openbare gallery en toegangscontrole op basis van leeftijdsrating.</p><h2 id="wat-automatische-tags-kunnen-doen" tabindex="-1">Wat automatische tags kunnen doen <a class="header-anchor" href="#wat-automatische-tags-kunnen-doen" aria-label="Permalink to &quot;Wat automatische tags kunnen doen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Functie</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Contenttags genereren</td><td>Voegt tags toe voor personen, scènes, objecten, kunststijl en vergelijkbare visuele inhoud.</td></tr><tr><td>Personagetags genereren</td><td>Handig voor anime-afbeeldingen en illustraties.</td></tr><tr><td>Oriëntatietags toevoegen</td><td>Voegt <code>landscape</code>, <code>portrait</code> of <code>square</code> toe.</td></tr><tr><td>Afbeeldingsrating toevoegen</td><td>Slaat <code>G/S/Q/E</code>-resultaten op voor algemeen, gevoelig, twijfelachtig of expliciet materiaal.</td></tr><tr><td>Automatisch taggen bij upload</td><td>Nieuwe afbeeldingen gaan automatisch door de taggingflow.</td></tr><tr><td>Batchtagging</td><td>Voegt tags toe aan oude afbeeldingen in alle mappen of geselecteerde mappen.</td></tr></tbody></table><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><p>Bereid minstens één toegankelijke Hugging Face Space-URL voor.</p><p>De aanbevolen aanpak is om SmilingWolfs <code>wd-tagger</code> Space naar je eigen Hugging Face-account te dupliceren:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Je kunt tijdelijk de openbare Space gebruiken, maar openbare Spaces worden door veel gebruikers gedeeld en kunnen wachtrijen, vertraging of uitval hebben. Een gedupliceerde Space onder je eigen account is stabieler voor langdurig automatisch taggen.</p><h2 id="smilingwolfs-space-dupliceren" tabindex="-1">SmilingWolfs Space dupliceren <a class="header-anchor" href="#smilingwolfs-space-dupliceren" aria-label="Permalink to &quot;SmilingWolfs Space dupliceren&quot;">​</a></h2><ol><li>Log in bij Hugging Face.</li><li>Open <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+a+`" alt="Openbare Space van SmilingWolf" loading="lazy"></p><ol start="3"><li>Klik rechtsboven op het menu met drie puntjes.</li><li>Kies <code>Duplicate this Space</code>.</li><li>Laat de standaardnaam staan of kies een eigen naam, zoals <code>wd-tagger</code>.</li><li>Zet zichtbaarheid op <code>Public</code>. Openbare Spaces zijn makkelijker door ImgBed aan te roepen.</li><li>Laat eerst de gratis standaardhardware staan. Upgrade later alleen als wachtrijen duidelijk een probleem worden.</li><li>Maak de Space aan en wacht tot de build klaar is.</li></ol><p>Na de build open je je Space-pagina. De URL ziet er meestal zo uit:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Kopieer de browser-URL en plak deze in ImgBeds <code>Space URLs</code>.</p><h2 id="meerdere-space-url-s-invullen" tabindex="-1">Meerdere Space URL&#39;s invullen <a class="header-anchor" href="#meerdere-space-url-s-invullen" aria-label="Permalink to &quot;Meerdere Space URL&#39;s invullen&quot;">​</a></h2><p>Vul één Space-URL per regel in.</p><p>Voorbeelden:</p><table tabindex="0"><thead><tr><th>Waarde</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Openbare SmilingWolf Space. Goed voor tijdelijk testen.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL van een gekopieerde Space-pagina.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Je eigen gedupliceerde Space-pagina.</td></tr></tbody></table><p>Je kunt meerdere URL&#39;s invoeren. ImgBed gebruikt meerdere Spaces samen, wat de snelheid kan verbeteren.</p><p>Als één Space tijdelijk niet beschikbaar is, kunnen de andere doorgaan.</p><h2 id="instellingen" tabindex="-1">Instellingen <a class="header-anchor" href="#instellingen" aria-label="Permalink to &quot;Instellingen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Aanbeveling</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Vul de voorbereide Space-URL&#39;s in. Gebruik er minstens één.</td></tr><tr><td>Doelmap</td><td>Laat leeg voor alle mappen. Selecteer alleen een map als je een specifieke directory wilt verwerken.</td></tr><tr><td>Herkenningsmodel</td><td>Laat standaard <code>wd-swinv2-tagger-v3</code> staan.</td></tr><tr><td>Drempel algemene tags</td><td>De standaardwaarde werkt voor de meeste afbeeldingen. Lagere waarden geven meer tags, hogere waarden minder.</td></tr><tr><td>Drempel personagetags</td><td>Standaard conservatief, zodat verkeerde personagetags worden beperkt.</td></tr><tr><td>Automatische <code>MCut</code>-drempel</td><td>Laat eerst uit. Zet aan als het model zelf het aantal tags moet bepalen.</td></tr><tr><td>Automatisch taggen bij upload</td><td>Zet aan als nieuwe uploads automatisch tags moeten krijgen.</td></tr><tr><td>Tagging starten</td><td>Start handmatig batchtagging voor oude afbeeldingen.</td></tr></tbody></table><h2 id="aanbevolen-startwaarden" tabindex="-1">Aanbevolen startwaarden <a class="header-anchor" href="#aanbevolen-startwaarden" aria-label="Permalink to &quot;Aanbevolen startwaarden&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Aanbevolen waarde</th></tr></thead><tbody><tr><td>Herkenningsmodel</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Drempel algemene tags</td><td><code>0.35</code></td></tr><tr><td>Drempel personagetags</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Eerst uit</td></tr><tr><td>Automatisch taggen bij upload</td><td>Inschakelen indien nodig</td></tr></tbody></table><p>Krijg je te veel tags, verhoog dan de algemene drempel iets.</p><p>Krijg je te weinig tags, verlaag dan de algemene drempel iets.</p><h2 id="batchtagging" tabindex="-1">Batchtagging <a class="header-anchor" href="#batchtagging" aria-label="Permalink to &quot;Batchtagging&quot;">​</a></h2><ol><li>Vul <code>Space URLs</code> in.</li><li>Selecteer een doelmap.</li><li>Klik op tagging starten.</li><li>Wacht tot de voortgang klaar is.</li></ol><p>Als de doelmap leeg is, verwerkt ImgBed alle mappen.</p><p>Batchtagging is vooral geschikt voor oude afbeeldingen. Voor nieuwe afbeeldingen schakel je automatisch taggen bij upload in, zodat je dit niet telkens handmatig hoeft te starten.</p><h2 id="automatisch-taggen-bij-upload" tabindex="-1">Automatisch taggen bij upload <a class="header-anchor" href="#automatisch-taggen-bij-upload" aria-label="Permalink to &quot;Automatisch taggen bij upload&quot;">​</a></h2><p>Wanneer dit is ingeschakeld, roepen nieuw geüploade afbeeldingen automatisch de ingestelde <code>Space URLs</code> aan.</p><p>Dit is geschikt voor langdurig gebruik.</p><p>Als je Space in de wachtrij staat, kan de upload zelf toch eerst afronden en loopt tagging daarna door.</p><h2 id="welke-afbeeldingen-worden-verwerkt" tabindex="-1">Welke afbeeldingen worden verwerkt <a class="header-anchor" href="#welke-afbeeldingen-worden-verwerkt" aria-label="Permalink to &quot;Welke afbeeldingen worden verwerkt&quot;">​</a></h2><p>Automatische tagging verwerkt vooral afbeeldingsbestanden.</p><p>Afbeeldingen die al volledige tags, oriëntatie, rating, breedte en hoogte hebben, worden overgeslagen om onnodige Space-aanroepen te voorkomen.</p><p>ImgBed vult waar mogelijk alleen ontbrekende informatie aan. Ontbreekt bijvoorbeeld alleen oriëntatie, dan probeert het die toe te voegen zonder de volledige contenttagflow aan te roepen.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="waarom-mijn-eigen-space-dupliceren" tabindex="-1">Waarom mijn eigen Space dupliceren? <a class="header-anchor" href="#waarom-mijn-eigen-space-dupliceren" aria-label="Permalink to &quot;Waarom mijn eigen Space dupliceren?&quot;">​</a></h3><p>Openbare Spaces worden door veel gebruikers gedeeld. Je eigen gedupliceerde Space wordt vooral door jouw ImgBed-site gebruikt en is daardoor meestal sneller en betrouwbaarder.</p><h3 id="de-space-blijft-opstarten" tabindex="-1">De Space blijft opstarten <a class="header-anchor" href="#de-space-blijft-opstarten" aria-label="Permalink to &quot;De Space blijft opstarten&quot;">​</a></h3><p>Na de eerste aanmaak of na een lange periode zonder gebruik kan een Space tijd nodig hebben om te starten.</p><p>Open eerst je Space-pagina. Zodra deze normaal een afbeelding kan herkennen, ga je terug naar ImgBed en start je tagging.</p><h3 id="hoe-kopieer-ik-de-space-url" tabindex="-1">Hoe kopieer ik de Space-URL? <a class="header-anchor" href="#hoe-kopieer-ik-de-space-url" aria-label="Permalink to &quot;Hoe kopieer ik de Space-URL?&quot;">​</a></h3><p>Open je Hugging Face Space-pagina en kopieer het browseradres.</p><p>Voorbeelden:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="kan-ik-meerdere-spaces-toevoegen" tabindex="-1">Kan ik meerdere Spaces toevoegen? <a class="header-anchor" href="#kan-ik-meerdere-spaces-toevoegen" aria-label="Permalink to &quot;Kan ik meerdere Spaces toevoegen?&quot;">​</a></h3><p>Ja. Vul één Space-URL per regel in.</p><p>Meerdere Spaces verwerken afbeeldingen samen en zijn handig wanneer je veel afbeeldingen hebt.</p><h3 id="waarom-zijn-tags-in-het-engels" tabindex="-1">Waarom zijn tags in het Engels? <a class="header-anchor" href="#waarom-zijn-tags-in-het-engels" aria-label="Permalink to &quot;Waarom zijn tags in het Engels?&quot;">​</a></h3><p>SmilingWolf-modellen geven Engelse tags terug. Dat is normaal.</p><p>De tags worden vooral gebruikt voor zoeken, filtering, de Random Image API en openbare galleryfilters.</p><h3 id="waarvoor-worden-ratingtags-gebruikt" tabindex="-1">Waarvoor worden ratingtags gebruikt? <a class="header-anchor" href="#waarvoor-worden-ratingtags-gebruikt" aria-label="Permalink to &quot;Waarvoor worden ratingtags gebruikt?&quot;">​</a></h3><p>Ratingresultaten werken samen met de toegangsmodus in Beveiligingsinstellingen.</p><p>Wanneer bezoekerstoegang bijvoorbeeld op leeftijdsrating is beperkt, filteren openbare browsefuncties en random image-functies afbeeldingen volgens die regels.</p><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Log in bij Hugging Face</span></span>
<span class="line"><span>-&gt; Open SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Wacht tot de Space is gebouwd</span></span>
<span class="line"><span>-&gt; Kopieer je Space-URL</span></span>
<span class="line"><span>-&gt; Vul Space URLs in ImgBed in</span></span>
<span class="line"><span>-&gt; Kies model en drempels</span></span>
<span class="line"><span>-&gt; Start tagging of schakel automatisch taggen bij upload in</span></span></code></pre></div>`,63)])])}const m=t(r,[["render",d]]);export{b as __pageData,m as default};
